import React from 'react';

export default function Home() {
  return (
    <div>
      <h2>Welcome!</h2>
      <p>Use the buttons above to either generate a new secure QR or decrypt existing data.</p>
      <button onClick={() => window.location.href = '/generate'}>Generate QR</button>
      <button style={{ marginLeft: '10px' }} onClick={() => window.location.href = '/decrypt'}>Decrypt Text</button>
    </div>
  );
}
